import pytest
import requests

BASE_URL = "http://fhir-lite.local"

@pytest.fixture
def unregistered_device_session():
    return <fixture_unregistered_device_session>

def test_unregistered_device_cert_rejected_with_401(unregistered_device_session):
    payload = {
        "resourceType": "Observation",
        "status": "final",
        "code": {"coding": [{"system": "http://loinc.org", "code": "8867-4"}]},
        "effectiveDateTime": "2024-06-01T12:00:00Z",
        "valueQuantity": {"value": 72.0, "unit": "beats/min"}
    }
    resp = unregistered_device_session.post(f"{BASE_URL}/Ingest", json=payload)
    assert resp.status_code == 401
    body = resp.json()
    assert body.get("resourceType") == "OperationOutcome"
    severities = [i["severity"] for i in body.get("issue", [])]
    assert "error" in severities

import pytest
import requests

BASE_URL = "http://fhir-lite.local"

@pytest.fixture
def pending_device_session():
    return <fixture_pending_device_session>

@pytest.fixture
def device_registration_token():
    return <fixture_device_registration_token>

def test_state_transition_device_registers_then_ingests(
    pending_device_session, device_registration_token
):
    payload = {
        "resourceType": "Observation",
        "status": "final",
        "code": {"coding": [{"system": "http://loinc.org", "code": "8867-4"}]},
        "effectiveDateTime": "2024-06-01T10:00:00Z",
        "valueQuantity": {"value": 98.6, "unit": "degF"}
    }
    pre_resp = pending_device_session.post(f"{BASE_URL}/Ingest", json=payload)
    assert pre_resp.status_code == 401
    reg_resp = requests.post(
        f"{BASE_URL}/Device",
        headers={"Authorization": f"Bearer {device_registration_token}"},
        json=<fixture_device_registration_body>
    )
    assert reg_resp.status_code in (200, 201)
    post_resp = pending_device_session.post(f"{BASE_URL}/Ingest", json=payload)
    assert post_resp.status_code == 201
    assert "id" in post_resp.json()

import pytest
import requests

BASE_URL = "http://fhir-lite.local"

@pytest.fixture
def device_sessions():
    return <fixture_four_device_sessions>

@pytest.mark.parametrize("cert_valid,registered,expected_status", [
    (True,  True,  201),
    (True,  False, 401),
    (False, True,  401),
    (False, False, 401),
])
def test_decision_table_cert_validity_x_registration_status(
    device_sessions, cert_valid, registered, expected_status
):
    session = device_sessions[(cert_valid, registered)]
    payload = {
        "resourceType": "Observation",
        "status": "final",
        "code": {"coding": [{"system": "http://loinc.org", "code": "8867-4"}]},
        "effectiveDateTime": "2024-06-01T08:00:00Z",
        "valueQuantity": {"value": 37.0, "unit": "Cel"}
    }
    resp = session.post(f"{BASE_URL}/Ingest", json=payload)
    assert resp.status_code == expected_status
